function KanbanBoard({ projects, onCardClick, onPhaseChange }) {
  const [dragOver, setDragOver] = useState(null);

  const columns = KANBAN_PHASES.map(phase => ({
    phase,
    items: projects.filter(p => getCurrentPhase(p) === phase),
  }));

  return (
    <div className="flex gap-3 overflow-x-auto pb-4" style={{ minHeight: '60vh' }}>
      {columns.map(({ phase, items }) => {
        const c = KANBAN_COLORS[phase];
        const isOver = dragOver === phase;
        return (
          <div
            key={phase}
            className="flex-shrink-0 w-64 rounded-2xl transition-all duration-200"
            style={{
              background: isOver ? c.bg : 'rgba(248, 250, 252, 0.7)',
              backdropFilter: 'blur(16px)',
              WebkitBackdropFilter: 'blur(16px)',
              border: isOver ? `1.5px dashed ${c.accent}` : '1px solid rgba(226, 232, 240, 0.8)',
              boxShadow: isOver ? `0 0 24px ${c.glow}` : '0 1px 4px rgba(15, 23, 42, 0.04)',
            }}
            onDragOver={(e) => { if (onPhaseChange) { e.preventDefault(); setDragOver(phase); } }}
            onDragLeave={() => setDragOver(null)}
            onDrop={(e) => {
              if (!onPhaseChange) return;
              e.preventDefault();
              const projectId = e.dataTransfer.getData('text/kanban-project');
              if (projectId) onPhaseChange(projectId, phase);
              setDragOver(null);
            }}
          >
            {/* 欄位標題 */}
            <div className="px-3.5 py-3 flex items-center justify-between sticky top-0">
              <div className="flex items-center gap-2">
                <span className="w-2 h-2 rounded-full" style={{ background: c.accent, boxShadow: `0 0 8px ${c.glow}` }} />
                <span className="text-sm font-semibold text-slate-700">{phase}</span>
              </div>
              <span className="text-xs px-2 py-0.5 rounded-full font-medium"
                style={{ background: c.bg, color: c.accent }}>{items.length}</span>
            </div>
            {/* 卡片 */}
            <div className="px-2.5 pb-3 space-y-2 overflow-y-auto" style={{ maxHeight: 'calc(100vh - 320px)' }}>
              {items.length === 0 ? (
                <div className="text-center py-8 text-[11px] text-slate-300">
                  {onPhaseChange ? '拖拉卡片到這裡' : '無產品'}
                </div>
              ) : items.map(p => (
                <KanbanCard
                  key={p.id}
                  project={p}
                  draggable={!!onPhaseChange}
                  onDragStart={(e) => e.dataTransfer.setData('text/kanban-project', String(p.id))}
                  onClick={() => onCardClick(p)}
                />
              ))}
            </div>
          </div>
        );
      })}
    </div>
  );
}

// 根據資料自動判斷目前階段
function computeAutoPhase(project) {
  // MP：料號已申請
  if (project.materialCodeStatus === '已申請') return 'MP';

  // PVT：試模或料號申請中（T1~T4 都算試產）
  const trialRounds = (project.trialRuns || []).map(r => r.round);
  if (project.materialCodeStatus === '申請中') return 'PVT';
  if (trialRounds.length > 0) return 'PVT';

  // DVT：DFM 完成（DFA/DFM 設計驗證）
  if (project.hasDFM && (project.dfmNotes || (project.dfmAttachments || []).length > 0)) return 'DVT';

  // EVT：有手板（工程驗證）
  if ((project.prototypeOrders || []).length > 0) return 'EVT';

  // 規劃：尚未開始手板
  return '規劃';
}

// 取得實際階段（手動覆蓋優先）
function getCurrentPhase(project) {
  if (project.phaseOverride) return project.phaseOverride;
  return computeAutoPhase(project);
}

// 取得階段內的詳細子進度文字
function getPhaseDetail(project) {
  const phase = getCurrentPhase(project);

  if (phase === '規劃') {
    const idCount = project.designs?.ID?.length || 0;
    const td = project.designs?.['3D']?.length || 0;
    const bom = project.designs?.BOM?.length || 0;
    if (idCount > 0 && td > 0 && bom > 0) return 'BOM 完成';
    if (idCount > 0 && td > 0) return '3D 完成';
    if (idCount > 0) return 'ID 完成';
    if (td > 0) return '3D 進行中';
    return '尚未開始';
  }

  if (phase === 'EVT') {
    const orders = project.prototypeOrders || [];
    const received = orders.filter(o => o.status === '已收到').length;
    return `手板 ${received}/${orders.length} 已收到`;
  }

  if (phase === 'DVT') {
    if (project.hasDFM) return 'DFM 進行中';
    return '進行中';
  }

  if (phase === 'PVT') {
    const trials = project.trialRuns || [];
    if (trials.length > 0) {
      const last = trials[trials.length - 1];
      return `${last.round} 完成`;
    }
    if ((project.mouldOrders || []).length > 0) return '模具下訂';
    if (project.materialCodeStatus === '申請中') return '料號申請中';
    return '試產中';
  }

  if (phase === 'MP') return '已量產';

  return '';
}

function ProjectRow({ project, onClick, draggable = false, isDragging = false, isDropTarget = false, onDragStart, onDragOver, onDragLeave, onDrop, onDragEnd }) {
  const latest = project.updates?.[0];
  const cfg = STATUS_COLORS[project.status];

  const mainImage = project.productImages?.[0];
  const currentPhase = getCurrentPhase(project);
  const phaseDetail = getPhaseDetail(project);
  const phaseColor = PHASE_COLORS[currentPhase];
  const isOverridden = !!project.phaseOverride;

  // 計算距離上次更新的天數
  const daysSinceUpdate = (() => {
    const effectiveDate = latest?.dateEnd || latest?.date;
    if (!effectiveDate) return null;
    const last = new Date(effectiveDate);
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    last.setHours(0, 0, 0, 0);
    return Math.floor((today - last) / 86400000);
  })();

  // 超過 14 天沒更新且還在進行中（非取消/暫停）的產品才顯示警示
  const isStale = daysSinceUpdate !== null
    && daysSinceUpdate >= 14
    && project.status !== '取消'
    && project.status !== '暫停'
    && project.status !== '設計完成';

  const staleColor = daysSinceUpdate >= 30
    ? 'text-rose-600 bg-rose-50 border-rose-200'
    : 'text-amber-600 bg-amber-50 border-amber-200';

  return (
    <div
      draggable={draggable}
      onDragStart={(e) => {
        if (!draggable) return;
        e.dataTransfer.effectAllowed = 'move';
        // 不要傳遞檔案資料，這是內部排序拖曳
        e.dataTransfer.setData('text/plain', 'reorder');
        if (onDragStart) onDragStart();
      }}
      onDragOver={(e) => {
        if (!draggable) return;
        e.preventDefault();
        if (onDragOver) onDragOver();
      }}
      onDragLeave={(e) => {
        if (!draggable) return;
        if (onDragLeave) onDragLeave();
      }}
      onDrop={(e) => {
        if (!draggable) return;
        e.preventDefault();
        if (onDrop) onDrop();
      }}
      onDragEnd={() => {
        if (onDragEnd) onDragEnd();
      }}
      className={`transition ${isDragging ? 'opacity-30' : ''} ${isDropTarget ? 'ring-2 ring-blue-400 ring-offset-1 rounded-xl' : ''}`}
    >
    <button
      onClick={onClick}
      className={`w-full text-left bg-white rounded-2xl p-4 transition-all duration-200 ease-out group hover:-translate-y-0.5 ${draggable ? 'cursor-grab active:cursor-grabbing' : ''}`}
      style={{
        border: '1px solid rgba(226, 232, 240, 0.9)',
        boxShadow: '0 1px 3px rgba(15, 23, 42, 0.04), 0 1px 2px rgba(15, 23, 42, 0.03)',
      }}
      onMouseEnter={(e) => { e.currentTarget.style.boxShadow = '0 12px 28px rgba(15, 23, 42, 0.1), 0 2px 8px rgba(15, 23, 42, 0.06)'; e.currentTarget.style.border = '1px solid rgba(203, 213, 225, 1)'; }}
      onMouseLeave={(e) => { e.currentTarget.style.boxShadow = '0 1px 3px rgba(15, 23, 42, 0.04), 0 1px 2px rgba(15, 23, 42, 0.03)'; e.currentTarget.style.border = '1px solid rgba(226, 232, 240, 0.9)'; }}
    >
      <div className="flex items-start gap-3">
        <div className="flex-shrink-0 w-16 h-16 sm:w-20 sm:h-20 rounded-xl bg-white border border-slate-100 overflow-hidden flex items-center justify-center">
          {mainImage ? (
            <StorageImage
              src={mainImage.url || mainImage.dataUrl}
              path={mainImage.path}
              alt={project.name}
              className="w-full h-full object-contain transition-transform duration-300 ease-out group-hover:scale-110"
              style={mainImage.fit === 'cover' ? { objectFit: 'cover' } : undefined}
            />
          ) : (
            <ImageIcon className="w-5 h-5 text-slate-300" />
          )}
        </div>

        <div className="min-w-0 flex-1">
          <div className="flex items-start justify-between gap-3 mb-2">
            <div className="min-w-0 flex-1">
              <div className="flex items-center gap-2 flex-wrap mb-1">
                <h3 className="text-[15px] font-semibold text-slate-900 line-clamp-1 tracking-tight">{project.name}</h3>
                {project.code && <span className="text-[11px] font-mono text-slate-400">{project.code}</span>}
                {project.materialCodeNumber && (
                  <span className="text-[11px] font-mono px-1.5 py-0.5 rounded bg-emerald-50 text-emerald-700 border border-emerald-200" title="正式料號">
                    料號 {project.materialCodeNumber}
                  </span>
                )}
              </div>
              <div className="flex items-center gap-2 flex-wrap">
                <span className={`text-xs px-2 py-0.5 rounded border ${cfg}`}>{project.status}</span>
                {project.supplier && (
                  <span className="text-xs px-2 py-0.5 rounded bg-slate-50 text-slate-600 border border-slate-200">
                    {project.supplier}
                  </span>
                )}
                {(project.tags || []).map(t => (
                  <span key={t} className="text-xs px-2 py-0.5 rounded bg-violet-50 text-violet-700 border border-violet-200">
                    {t}
                  </span>
                ))}
              </div>
            </div>
            <div className="flex-shrink-0 text-right">
              <p className="text-xs text-slate-400 mb-0.5 flex items-center justify-end gap-1">
                目前階段
                {isOverridden && <span className="text-[9px] text-amber-600" title="已手動覆蓋">●</span>}
              </p>
              <span className={`inline-flex items-center gap-1 text-xs px-2 py-0.5 rounded border font-medium ${phaseColor.bg} ${phaseColor.text} ${phaseColor.border}`}>
                {currentPhase}
              </span>
            </div>
          </div>

          {latest && (
            <div className="mt-3 pt-3 border-t border-slate-100">
              <div className="flex items-baseline gap-2 mb-0.5 flex-wrap">
                <span className="text-xs text-blue-600 font-medium tabular-nums flex-shrink-0">
                  {latest.date}
                </span>
                <span className="text-xs text-slate-400">最新進度</span>
                {isStale && (
                  <span className={`text-[10px] px-1.5 py-0.5 rounded border font-medium flex-shrink-0 ${staleColor}`}>
                    {daysSinceUpdate}天未更新
                  </span>
                )}
              </div>
              <p className="text-sm text-slate-700 line-clamp-2 leading-relaxed">{latest.text}</p>
              {project.updates.length > 1 && (
                <p className="text-xs text-slate-400 mt-1.5">+ {project.updates.length - 1} 筆歷史紀錄</p>
              )}
            </div>
          )}
          {!latest && project.status !== '取消' && project.status !== '暫停' && (
            <div className="mt-3 pt-3 border-t border-slate-100">
              <span className="text-[10px] px-1.5 py-0.5 rounded border text-slate-400 bg-slate-50 border-slate-200">
                尚無進度紀錄
              </span>
            </div>
          )}
        </div>
      </div>
    </button>
    </div>
  );
}

// ── 產品大類 / 小類資料 ────────────────────────────────────────
