function RFPField({ label, required, children }) {
  return (
    <div className="mb-2">
      <label className="text-xs text-slate-500 mb-0.5 block">
        {required && <span className="text-rose-500 mr-0.5">*</span>}{label}
      </label>
      {children}
    </div>
  );
}

function RFPInput({ value, onChange, ...props }) {
  return (
    <input value={value} onChange={onChange}
      className="w-full px-2 py-1.5 text-sm border border-slate-200 rounded focus:outline-none focus:border-slate-400" {...props} />
  );
}

// 支援圖片貼上的富文本欄位（用於 RFP 需求欄位）
function RFPRichField({ value, onChange }) {
  const ref = React.useRef(null);

  React.useEffect(() => {
    if (!ref.current) return;
    // 只在初始化時設定內容（避免游標跳動）
    if (ref.current.innerHTML !== value) {
      ref.current.innerHTML = value || '';
    }
  }, []);

  const handleInput = () => {
    onChange(ref.current?.innerHTML || '');
  };

  const handlePaste = (e) => {
    const items = e.clipboardData?.items || [];
    // 圖片貼上：插入 base64
    for (const item of items) {
      if (item.type.startsWith('image/')) {
        e.preventDefault();
        e.stopPropagation();
        const file = item.getAsFile();
        const reader = new FileReader();
        reader.onload = ev => {
          document.execCommand('insertHTML', false,
            `<img src="${ev.target.result}" style="max-width:100%;margin:4px 0;border-radius:4px;" />`
          );
          onChange(ref.current?.innerHTML || '');
        };
        reader.readAsDataURL(file);
        return;
      }
    }
    // 文字貼上：去掉所有格式，只保留純文字（避免帶入編號清單、表格等）
    const plain = e.clipboardData?.getData('text/plain') || '';
    if (plain) {
      e.preventDefault();
      e.stopPropagation();
      document.execCommand('insertText', false, plain);
      onChange(ref.current?.innerHTML || '');
    } else {
      e.stopPropagation();
    }
  };

  return (
    <div
      ref={ref}
      contentEditable
      suppressContentEditableWarning
      onInput={handleInput}
      onPaste={handlePaste}
      data-placeholder="點此輸入，可貼上文字或圖片..."
      className="w-full px-3 py-2 text-sm border border-slate-200 rounded focus:outline-none focus:border-slate-400 min-h-[80px] max-h-[300px] overflow-y-auto"
      style={{ lineHeight: '1.6' }}
    />
  );
}

// ── RFP Modal ──────────────────────────────────────────────────
function RFPModal({ project, currentUser, onClose, onSaveDraft }) {
  const today = new Date().toISOString().split('T')[0];
  const systemImages = (project.productImages || []).map((img, i) => ({
    id: `sys_${i}`,
    src: img.url || img.dataUrl || '',
    path: img.path || '',
    name: img.name || `圖片${i+1}`,
    isMain: i === 0,
  }));

  const [form, setForm] = useState(() => {
    const draft = project.rfpDraft || {};
    // 清理需求欄位的編號清單等格式，只保留 <img> 和換行
    const cleanReq = (html) => {
      if (!html) return '';
      // 移除 <ol> <ul> <li> 編號清單標籤，但保留內容
      let cleaned = html
        .replace(/<\/?(ol|ul)[^>]*>/gi, '')
        .replace(/<li[^>]*>/gi, '')
        .replace(/<\/li>/gi, '<br>')
        // 移除其他格式標籤（保留 img, br, p）
        .replace(/<(?!\/?(img|br|p)\b)[^>]+>/gi, '');
      return cleaned;
    };
    return {
      rfpNo: draft.rfpNo || '',
      applicant: draft.applicant || currentUser?.name || 'Nina',
      applyDate: draft.applyDate || today,
      categoryMain: draft.categoryMain || '',
      categorySub: draft.categorySub || '',
      devAttr: draft.devAttr || 'COMART自我開發',
      client: draft.client || '',
      reqDept: draft.reqDept || '國外業務',
      execDept: draft.execDept || '工程課',
      owner: draft.owner || '徐福威',
      productName: draft.productName || project.name || '',
      targetGroup: draft.targetGroup || '消費者',
      productReq: cleanReq(draft.productReq) || '',
      designReq: cleanReq(draft.designReq) || '',
      otherReq: cleanReq(draft.otherReq) || '',
      targetSales: draft.targetSales || '5K',
      amortQty: draft.amortQty || '5K',
      firstBatch: draft.firstBatch || '1K',
      toolingCost: draft.toolingCost || 'N/A',
      targetCost: draft.targetCost || 'N/A',
      fobCost: draft.fobCost || 'N/A',
      msrp: draft.msrp || 'N/A',
      schedKickoff: draft.schedKickoff || '',
      schedEVT: draft.schedEVT || '',
      schedDVT: draft.schedDVT || '',
      schedPVT: draft.schedPVT || '',
      schedMP: draft.schedMP || 'N/A',
      schedOnMarket: draft.schedOnMarket || 'N/A',
      // 圖片從草稿帶回（base64 直接存）
      selectedSystemImgIds: systemImages.filter(i => i.isMain).map(i => i.id),
      uploadedImages: draft.uploadedImages || [],
      deletedSystemImgIds: draft.deletedSystemImgIds || [],
    };
  });
  const [savedMsg, setSavedMsg] = useState('');
  const [resolvedUrls, setResolvedUrls] = useState({});
  const [imgLoading, setImgLoading] = useState(systemImages.length > 0);

  React.useEffect(() => {
    if (systemImages.length === 0) { setImgLoading(false); return; }
    Promise.all(
      systemImages.map(async (img) => {
        try {
          if (img.path) {
            const url = await getStorageUrl(img.path);
            if (url) return [img.id, url];
          }
          if (img.src) return [img.id, img.src];
        } catch {}
        return [img.id, null];
      })
    ).then(results => {
      const map = {};
      results.forEach(([id, url]) => { if (url) map[id] = url; });
      setResolvedUrls(map);
      setImgLoading(false);
    });
  }, []);

  // 貼上圖片（Ctrl+V）
  const handlePaste = (e) => {
    const items = e.clipboardData?.items || [];
    for (const item of items) {
      if (item.type.startsWith('image/')) {
        const file = item.getAsFile();
        const reader = new FileReader();
        reader.onload = ev => setForm(f => ({ ...f, uploadedImages: [...(f.uploadedImages || []), { src: ev.target.result, name: '貼上圖片' }] }));
        reader.readAsDataURL(file);
      }
    }
  };

  const set = (k, v) => setForm(f => ({ ...f, [k]: v }));
  const subCategories = form.categoryMain ? RFP_CATEGORIES[form.categoryMain] || [] : [];

  const saveDraft = () => {
    if (onSaveDraft) {
      onSaveDraft({ ...form }); // 包含 uploadedImages（base64 小截圖 OK）
      setSavedMsg('草稿已儲存');
      setTimeout(() => setSavedMsg(''), 2000);
    }
  };

  const handleImageUpload = (e) => {
    Array.from(e.target.files || []).forEach(file => {
      const reader = new FileReader();
      reader.onload = ev => setForm(f => ({ ...f, uploadedImages: [...(f.uploadedImages || []), { src: ev.target.result, name: file.name }] }));
      reader.readAsDataURL(file);
    });
  };

  const toggleSystemImg = (id) => {
    setForm(f => {
      const ids = f.selectedSystemImgIds || [];
      return { ...f, selectedSystemImgIds: ids.includes(id) ? ids.filter(x => x !== id) : [...ids, id] };
    });
  };

  const handleExportPDF = async () => {
    const deletedIds = form.deletedSystemImgIds || [];
    const activeSysImgs = systemImages.filter(img => !deletedIds.includes(img.id));
    const toBase64 = async (url) => {
      try {
        const res = await fetch(url);
        const blob = await res.blob();
        return await new Promise(r => { const rd = new FileReader(); rd.onload = e => r(e.target.result); rd.readAsDataURL(blob); });
      } catch { return url; }
    };
    const sysImgHtml = (await Promise.all(activeSysImgs.map(async img => {
      const url = resolvedUrls[img.id] || img.src;
      if (!url) return '';
      const src = url.startsWith('data:') ? url : await toBase64(url);
      return `<img src="${src}" style="max-width:160px;max-height:110px;object-fit:contain;margin:3px;border-radius:4px;border:1px solid #e2e8f0;" />`;
    }))).join('');
    const upImgHtml = (form.uploadedImages || []).map(img =>
      `<img src="${img.src}" style="max-width:160px;max-height:110px;object-fit:contain;margin:3px;border-radius:4px;border:1px solid #e2e8f0;" />`
    ).join('');
    const allImgHtml = sysImgHtml + upImgHtml;

    const esc = s => (s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;');
    const html = `<!DOCTYPE html><html lang="zh-TW"><head><meta charset="UTF-8"/>
<title>COMART RFP - ${form.productName}</title>
<style>
body{font-family:'Microsoft JhengHei','PingFang TC',sans-serif;font-size:12px;color:#1e293b;margin:0;padding:20px;}
h1{text-align:center;font-size:15px;letter-spacing:2px;margin-bottom:3px;}
.sub{text-align:center;font-size:10px;color:#64748b;margin-bottom:10px;}
.top{display:flex;justify-content:space-between;font-size:11px;margin-bottom:8px;}
.imgs{display:flex;flex-wrap:wrap;gap:6px;padding:8px;border:1px solid #e2e8f0;border-radius:6px;background:#f8fafc;margin-bottom:8px;}
table{width:100%;border-collapse:collapse;margin-bottom:7px;font-size:11px;}
td,th{border:1px solid #cbd5e1;padding:4px 7px;vertical-align:top;}
th{background:#f1f5f9;font-weight:600;white-space:nowrap;width:18%;}
.sec{background:#e2e8f0;font-weight:700;font-size:11px;padding:3px 7px;margin-bottom:0;}
.pre{white-space:pre-wrap;min-height:32px;}
.pre img{max-width:100%;border-radius:4px;margin:2px 0;}
.sign{display:flex;gap:24px;margin-top:12px;}
.sb{flex:1;border-top:1px solid #cbd5e1;padding-top:5px;font-size:11px;}
.note{font-size:10px;color:#94a3b8;margin-top:5px;}
@media print{body{padding:12px;}}
</style></head><body>
<h1>COMART REQUEST FOR PROPOSAL</h1>
<div class="sub">Request For Proposal 需求建議書</div>
<div class="top"><span>RFP# ${form.rfpNo||'－'}</span><span>申請日期：${form.applyDate}</span><span>申請人：${form.applicant}</span></div>
${allImgHtml ? `<div class="imgs">${allImgHtml}</div>` : ''}
<table>
<tr><th>產品大類</th><td>${esc(form.categoryMain)||'－'}</td><th>產品小類</th><td>${esc(form.categorySub)||'－'}</td></tr>
<tr><th>開發需求屬性</th><td>${esc(form.devAttr)||'－'}</td><th>客戶</th><td>${esc(form.client)||'－'}</td></tr>
<tr><th>需求單位</th><td>${esc(form.reqDept)}</td><th>執行單位</th><td>${esc(form.execDept)}</td></tr>
<tr><th>負責人員</th><td>${esc(form.owner)}</td><th>目標族群</th><td>${esc(form.targetGroup)}</td></tr>
<tr><th>產品名稱</th><td colspan="3">${esc(form.productName)}</td></tr>
<tr><th>產品需求</th><td colspan="3" class="pre">${form.productReq||'－'}</td></tr>
<tr><th>設計需求</th><td colspan="3" class="pre">${form.designReq||'－'}</td></tr>
<tr><th>其他需求</th><td colspan="3" class="pre">${form.otherReq||'－'}</td></tr>
</table>
<div class="sec">數量與成本</div>
<table><tr><th>目標銷量</th><td>${form.targetSales}</td><th>攤提數量</th><td>${form.amortQty}</td><th>首批單量</th><td>${form.firstBatch}</td></tr>
<tr><th>目標模具費</th><td>${form.toolingCost}</td><th>FOB cost</th><td>${form.fobCost}</td><th>MSRP</th><td>${form.msrp}</td></tr></table>
<div class="sec">時程需求</div>
<table><tr><th>Kick-off</th><td>${form.schedKickoff||'－'}</td><th>EVT</th><td>${form.schedEVT||'－'}</td><th>DVT</th><td>${form.schedDVT||'－'}</td></tr>
<tr><th>PVT</th><td>${form.schedPVT||'－'}</td><th>MP</th><td>${form.schedMP}</td><th>On Market</th><td>${form.schedOnMarket}</td></tr></table>
<div class="sign">
<div class="sb">提案人：${form.applicant}</div>
<div class="sb">業務主管簽章：</div>
<div class="sb">總經理簽章：</div>
</div>
<p class="note">* 前方欄位有「*」者表示必填</p>
<script>window.onload=()=>{window.print();}</script>
</body></html>`;
    const w = window.open('', '_blank');
    if (!w) { alert('請允許瀏覽器開啟彈出視窗'); return; }
    w.document.write(html);
    w.document.close();
  };

  return (
    <div className="modal-anim backdrop-blur-sm fixed inset-0 bg-slate-900/60 z-50 flex items-start justify-center p-4 overflow-y-auto" onPaste={handlePaste}>
      <div className="bg-white w-full max-w-3xl rounded-xl shadow-xl my-4">
        <div className="flex items-center justify-between px-5 py-3 border-b border-slate-200 sticky top-0 bg-white z-10 rounded-t-xl">
          <h2 className="text-sm font-semibold text-slate-800">產生 RFP</h2>
          <div className="flex items-center gap-2">
            {savedMsg && <span className="text-xs text-emerald-600">{savedMsg}</span>}
            <button onClick={saveDraft} className="px-3 py-1.5 bg-slate-100 text-slate-700 text-sm rounded-lg hover:bg-slate-200">儲存草稿</button>
            <button onClick={handleExportPDF} className="px-3 py-1.5 bg-slate-900 text-white text-sm rounded-lg hover:bg-slate-700">↓ 導出 PDF</button>
            <button onClick={onClose} className="p-1.5 hover:bg-slate-100 rounded text-slate-500">✕</button>
          </div>
        </div>
        <div className="p-5 space-y-3">
          <div className="grid grid-cols-3 gap-3">
            <RFPField label="RFP#"><RFPInput value={form.rfpNo} onChange={e => set('rfpNo', e.target.value)} placeholder="選填" /></RFPField>
            <RFPField label="申請人" required><RFPInput value={form.applicant} onChange={e => set('applicant', e.target.value)} /></RFPField>
            <RFPField label="申請日期" required><RFPInput value={form.applyDate} onChange={e => set('applyDate', e.target.value)} type="date" /></RFPField>
          </div>

          {/* 產品圖片區 */}
          <div className="border border-slate-200 rounded-lg p-3">
            <p className="text-xs font-medium text-slate-600 mb-2">產品圖片 <span className="text-slate-400 font-normal">（滑鼠移上去顯示 ✕ 可刪除，可 Ctrl+V 貼上截圖）</span></p>
            <div className="flex flex-wrap gap-2 items-start">
              {imgLoading ? (
                <div className="text-xs text-slate-400 py-2">圖片載入中...</div>
              ) : (
                systemImages
                  .filter(img => !(form.deletedSystemImgIds || []).includes(img.id))
                  .map(img => {
                    const displaySrc = resolvedUrls[img.id];
                    if (!displaySrc) return null;
                    return (
                      <div key={img.id} className="relative border border-slate-200 rounded group">
                        <img src={displaySrc} alt={img.name} className="h-20 w-20 object-contain rounded" />
                        {img.isMain && <span className="absolute bottom-0 left-0 text-[8px] bg-blue-600 text-white px-1 rounded-tr">主圖</span>}
                        <button
                          onClick={() => set('deletedSystemImgIds', [...(form.deletedSystemImgIds || []), img.id])}
                          className="absolute -top-1 -right-1 w-4 h-4 bg-rose-500 text-white rounded-full text-[9px] items-center justify-center hidden group-hover:flex"
                        >✕</button>
                      </div>
                    );
                  })
              )}
              {(form.uploadedImages || []).map((img, i) => (
                <div key={i} className="relative border border-slate-200 rounded group">
                  <img src={img.src} alt={img.name} className="h-20 w-20 object-contain rounded" />
                  <button onClick={() => setForm(f => ({ ...f, uploadedImages: f.uploadedImages.filter((_, j) => j !== i) }))}
                    className="absolute -top-1 -right-1 w-4 h-4 bg-rose-500 text-white rounded-full text-[9px] items-center justify-center hidden group-hover:flex">✕</button>
                </div>
              ))}
              <label className="h-20 w-20 border-2 border-dashed border-slate-300 rounded flex flex-col items-center justify-center cursor-pointer hover:border-blue-400 text-slate-400 text-[10px] text-center">
                + 上傳
                <input type="file" accept="image/*" multiple className="hidden" onChange={handleImageUpload} />
              </label>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-3">
            <RFPField label="產品大類" required>
              <select value={form.categoryMain} onChange={e => { set('categoryMain', e.target.value); set('categorySub', ''); }}
                className="w-full px-2 py-1.5 text-sm border border-slate-200 rounded focus:outline-none bg-white">
                <option value="">請選擇</option>
                {Object.keys(RFP_CATEGORIES).map(k => <option key={k} value={k}>{k}</option>)}
              </select>
            </RFPField>
            <RFPField label="產品小類" required>
              <select value={form.categorySub} onChange={e => set('categorySub', e.target.value)}
                className="w-full px-2 py-1.5 text-sm border border-slate-200 rounded focus:outline-none bg-white" disabled={!form.categoryMain}>
                <option value="">請選擇</option>
                {subCategories.map(s => <option key={s} value={s}>{s}</option>)}
              </select>
            </RFPField>
          </div>
          <div className="grid grid-cols-2 gap-3">
            <RFPField label="開發需求屬性"><RFPInput value={form.devAttr} onChange={e => set('devAttr', e.target.value)} /></RFPField>
            <RFPField label="客戶"><RFPInput value={form.client} onChange={e => set('client', e.target.value)} placeholder="如 Scosche" /></RFPField>
          </div>
          <div className="grid grid-cols-3 gap-3">
            <RFPField label="需求單位" required><RFPInput value={form.reqDept} onChange={e => set('reqDept', e.target.value)} /></RFPField>
            <RFPField label="執行單位"><RFPInput value={form.execDept} onChange={e => set('execDept', e.target.value)} /></RFPField>
            <RFPField label="負責人員"><RFPInput value={form.owner} onChange={e => set('owner', e.target.value)} /></RFPField>
          </div>
          <div className="grid grid-cols-2 gap-3">
            <RFPField label="產品名稱" required><RFPInput value={form.productName} onChange={e => set('productName', e.target.value)} /></RFPField>
            <RFPField label="目標族群" required><RFPInput value={form.targetGroup} onChange={e => set('targetGroup', e.target.value)} /></RFPField>
          </div>
          {[
            { f: 'productReq', label: '產品需求（詳述使用情境、問題、功能效益，100字以上）', required: true },
            { f: 'designReq', label: '設計需求（尺寸重量、材質、功能、結構、色彩、風格等）' },
            { f: 'otherReq', label: '其他需求（附註說明、電器規格、參考圖檔、競品資訊連結等）' },
          ].map(({ f, label, required }) => (
            <RFPField key={f} label={label} required={required}>
              <RFPRichField
                value={form[f]}
                onChange={v => set(f, v)}
              />
            </RFPField>
          ))}
          <div>
            <p className="text-xs text-slate-500 mb-2 font-medium">數量與成本</p>
            <div className="grid grid-cols-3 gap-2 sm:grid-cols-6">
              {[['targetSales','目標銷量'],['amortQty','攤提數量'],['firstBatch','首批單量'],['toolingCost','目標模具費'],['fobCost','FOB cost'],['msrp','MSRP']].map(([f,l]) => (
                <div key={f}><p className="text-[10px] text-slate-400 mb-0.5">{l}</p>
                <input value={form[f]} onChange={e => set(f, e.target.value)} className="w-full px-2 py-1 text-xs border border-slate-200 rounded focus:outline-none" /></div>
              ))}
            </div>
          </div>
          <div>
            <p className="text-xs text-slate-500 mb-2 font-medium">時程需求</p>
            <div className="grid grid-cols-3 gap-2 sm:grid-cols-6">
              {[['schedKickoff','Kick-off'],['schedEVT','EVT'],['schedDVT','DVT'],['schedPVT','PVT'],['schedMP','MP'],['schedOnMarket','On Market']].map(([f,l]) => (
                <div key={f}><p className="text-[10px] text-slate-400 mb-0.5">{l}</p>
                <input value={form[f]} onChange={e => set(f, e.target.value)} className="w-full px-2 py-1 text-xs border border-slate-200 rounded focus:outline-none" /></div>
              ))}
            </div>
          </div>
          <div className="grid grid-cols-2 gap-4 pt-4 border-t border-slate-200">
            <div><p className="text-xs text-slate-500 mb-1">提案人</p><p className="text-sm font-medium">{form.applicant}</p></div>
            <div><p className="text-xs text-slate-500 mb-1">總經理</p><div className="h-8 border-b border-slate-300" /></div>
          </div>
          <p className="text-[10px] text-slate-400">* 前方欄位有「*」者表示必填</p>
        </div>
      </div>
    </div>
  );
}


function ProjectDetail({ project, allTags, isViewer, onClose, onAddUpdate, onEditUpdate, onDeleteUpdate, onUpdateField, onToggleStage, onDelete, onDuplicate, autoOpenWizard, onWizardClose, existingCodes = [], categoryCodes = DEFAULT_CATEGORY_CODES, featureCodes = DEFAULT_FEATURE_CODES, samples = [], withdrawals = [], customerLists = [], currentUser, openFrom = null, onReturn, followUpTrigger = null, onFollowUpTriggered }) {
  const [showWizard, setShowWizard] = useState(false);

  // 收到自動打開請求時，跳出精靈
  useEffect(() => {
    if (autoOpenWizard) {
      setShowWizard(true);
    }
  }, [autoOpenWizard]);

  const closeWizard = () => {
    setShowWizard(false);
    if (onWizardClose) onWizardClose();
  };
  const [showAddUpdate, setShowAddUpdate] = useState(false);
  const [followUpInitial, setFollowUpInitial] = useState(null);
  const [showFollowUpPrompt, setShowFollowUpPrompt] = useState(false);
  const [showRFP, setShowRFP] = useState(false);
  const [showEmailImport, setShowEmailImport] = useState(false);
  const [showHistory, setShowHistory] = useState(false);
  const [editingUpdateIdx, setEditingUpdateIdx] = useState(null);
  const [editingField, setEditingField] = useState(null);
  const [tempValue, setTempValue] = useState('');
  const [newTag, setNewTag] = useState('');
  const cfg = STATUS_COLORS[project.status];

  // 從提醒面板點「✓ 已跟追」跳過來時，先問有沒有新進度
  React.useEffect(() => {
    if (followUpTrigger) {
      setFollowUpInitial({
        date: new Date().toISOString().split('T')[0],
        author: currentUser?.name || '',
        text: '',
        followUpDate: '',
        _triggerUpdate: followUpTrigger,
      });
      setShowFollowUpPrompt(true); // 先跳對話框
      if (onFollowUpTriggered) onFollowUpTriggered();
    }
  }, [followUpTrigger]);

  // 直接標記已跟追（不填進度）
  const markTriggerFollowedUp = (triggerUpdate) => {
    if (!triggerUpdate) return;
    const allUpdates = project.updates || [];
    const idx = allUpdates.findIndex(x => x.date === triggerUpdate.date && x.text === triggerUpdate.text);
    if (idx >= 0) {
      const newUpdates = [...allUpdates];
      newUpdates[idx] = { ...newUpdates[idx], followedUp: true };
      onUpdateField('updates', newUpdates);
    }
  };

  const updates = project.updates || [];
  const latest = updates[0];
  const history = updates.slice(1);

  // 標記進度更新「已跟追」
  const handleMarkFollowedUp = (update) => {
    const idx = updates.findIndex(u => u === update || (u.date === update.date && u.text === update.text));
    if (idx < 0) return;
    const newUpdates = [...updates];
    newUpdates[idx] = { ...update, followedUp: true };
    onUpdateField('updates', newUpdates);
  };

  // 設定（或清除）進度的下次跟追日期
  const handleSetFollowUpDate = (update, date) => {
    const idx = updates.findIndex(u => u === update || (u.date === update.date && u.text === update.text));
    if (idx < 0) return;
    const newUpdates = [...updates];
    newUpdates[idx] = { ...newUpdates[idx], followUpDate: date || null, followedUp: date ? false : newUpdates[idx].followedUp };
    onUpdateField('updates', newUpdates);
  };

  const startEditField = (field, currentValue) => {
    setEditingField(field);
    setTempValue(currentValue || '');
  };

  const saveField = () => {
    // 料號重複偵測：如果新值已存在於其他產品，警告但仍儲存（讓使用者決定）
    if (editingField === 'code' && tempValue && tempValue !== project.code) {
      if (isCodeDuplicate(tempValue, existingCodes)) {
        if (!confirm(`料號「${tempValue}」已被其他產品使用。\n\n仍要儲存嗎？`)) {
          setEditingField(null);
          return;
        }
      }
    }
    onUpdateField(editingField, tempValue);
    setEditingField(null);
  };

  const handleAddTag = () => {
    if (!newTag.trim()) return;
    let tag = newTag.trim();
    if (!tag.startsWith('#')) tag = '#' + tag;
    if (!(project.tags || []).includes(tag)) {
      onUpdateField('tags', [...(project.tags || []), tag]);
    }
    setNewTag('');
  };

  const handleRemoveTag = (tag) => {
    onUpdateField('tags', (project.tags || []).filter(t => t !== tag));
  };

  return (
    <div className="fixed inset-0 z-40 flex items-start sm:items-center justify-center p-0 sm:p-4 overflow-y-auto"
      style={{ background: 'rgba(15, 23, 42, 0.45)', backdropFilter: 'blur(6px)', WebkitBackdropFilter: 'blur(6px)' }}>
      <div className="bg-white w-full sm:max-w-3xl sm:rounded-xl min-h-screen sm:min-h-0 sm:max-h-[92vh] flex flex-col"
        style={{
          animation: 'pdModalIn 0.22s cubic-bezier(0.16, 1, 0.3, 1)',
          boxShadow: '0 24px 64px rgba(15, 23, 42, 0.3)',
        }}>
        <style>{`@keyframes pdModalIn { from { opacity: 0; transform: scale(0.97) translateY(8px); } to { opacity: 1; transform: scale(1) translateY(0); } }`}</style>
        {/* 返回按鈕列（從其他面板跳來才顯示） */}
        {openFrom && onReturn && (() => {
          const backLabels = {
            samples: { icon: '📦', label: '樣品庫', title: '返回樣品庫' },
            reminders: { icon: '🔔', label: '提醒', title: '返回提醒面板' },
            prototype: { icon: '🧪', label: '手板總覽', title: '返回手板總覽' },
          };
          const back = backLabels[openFrom];
          if (!back) return null;
          return (
            <div className="px-4 pt-3 pb-0">
              <button
                onClick={onReturn}
                className="inline-flex items-center gap-1 text-xs text-amber-700 hover:text-amber-800 hover:bg-amber-50 px-2 py-1 rounded border border-amber-200 transition"
                title={back.title}
              >
                <ChevronLeft className="w-3.5 h-3.5" />
                {back.icon} 返回{back.label}
              </button>
            </div>
          );
        })()}
        <div className="flex items-start justify-between px-5 py-4 border-b border-slate-200 sticky top-0 bg-white z-10">
          <div className="flex-1 min-w-0 pr-3">
            {editingField === 'name' ? (
              <input
                type="text"
                value={tempValue}
                onChange={(e) => setTempValue(e.target.value)}
                onBlur={saveField}
                onKeyDown={(e) => { if (e.key === 'Enter') saveField(); if (e.key === 'Escape') setEditingField(null); }}
                autoFocus
                className="w-full text-base font-medium border border-slate-300 rounded px-2 py-1"
              />
            ) : (
              <h2
                className="text-base font-medium leading-snug cursor-text hover:bg-slate-50 -mx-2 px-2 py-1 rounded"
                onClick={() => startEditField('name', project.name)}
              >
                {project.name}
              </h2>
            )}
            <div className="flex items-center gap-2 mt-1.5 flex-wrap">
              <select
                value={project.status}
                onChange={(e) => onUpdateField('status', e.target.value)}
                className={`text-xs px-2 py-0.5 rounded border cursor-pointer ${cfg}`}
              >
                {STATUS_OPTIONS.map(s => <option key={s} value={s}>{s}</option>)}
              </select>
              {editingField === 'code' ? (
                <div className="inline-flex flex-col">
                  <input
                    type="text"
                    value={tempValue}
                    onChange={(e) => setTempValue(e.target.value.toUpperCase())}
                    onBlur={saveField}
                    onKeyDown={(e) => { if (e.key === 'Enter') saveField(); if (e.key === 'Escape') setEditingField(null); }}
                    autoFocus
                    placeholder="料號"
                    className={`text-xs border rounded px-2 py-0.5 w-36 font-mono ${
                      tempValue && tempValue !== project.code && isCodeDuplicate(tempValue, existingCodes)
                        ? 'border-rose-400 bg-rose-50 text-rose-700'
                        : 'border-slate-300'
                    }`}
                  />
                  {tempValue && tempValue !== project.code && isCodeDuplicate(tempValue, existingCodes) && (
                    <span className="text-[10px] text-rose-600 mt-0.5">⚠ 此料號已存在</span>
                  )}
                </div>
              ) : (
                <span
                  onClick={() => startEditField('code', project.code)}
                  className="text-xs text-slate-500 cursor-text hover:bg-slate-100 px-1 py-0.5 rounded font-mono"
                >
                  {project.code || '+ 料號'}
                </span>
              )}
              {!isViewer && (
                <button
                  onClick={() => setShowWizard(true)}
                  title="用編碼精靈產生料號"
                  className="text-[11px] text-blue-600 hover:bg-blue-50 px-1.5 py-0.5 rounded inline-flex items-center gap-0.5"
                >
                  <span>✨</span><span className="hidden sm:inline">編碼精靈</span>
                </button>
              )}
            </div>
          </div>
          <div className="flex items-center gap-1 flex-shrink-0">
            {/* 分享連結按鈕 */}
            <button
              onClick={() => {
                const base = window.location.origin + window.location.pathname;
                const hash = project.code ? `#${project.code}` : `#id=${project.id}`;
                const url = base + hash;
                navigator.clipboard.writeText(url).then(() => {
                  // 臨時顯示「已複製」
                  const btn = document.getElementById('share-btn-' + project.id);
                  if (btn) {
                    const orig = btn.innerHTML;
                    btn.innerHTML = '✓ 已複製';
                    setTimeout(() => { btn.innerHTML = orig; }, 1500);
                  }
                }).catch(() => {
                  prompt('複製此連結：', url);
                });
              }}
              id={`share-btn-${project.id}`}
              title="複製此產品的分享連結（可傳給工程/老闆，點連結直接開此產品）"
              className="p-1.5 hover:bg-slate-100 rounded text-slate-400 hover:text-slate-700 inline-flex items-center gap-1 text-xs px-2"
            >
              <span>🔗</span>
              <span className="hidden sm:inline">分享</span>
            </button>
            {!isViewer && onDuplicate && (
              <button
                onClick={() => {
                  if (confirm(`確定要複製「${project.name}」嗎？\n會建立一個新專案，所有資料（圖片、版本、進度、訂單等）都會複製過去，只有料號需要重新編碼。`)) {
                    onDuplicate();
                  }
                }}
                title="複製此專案（建立新副本）"
                className="p-1.5 hover:bg-blue-50 rounded text-slate-400 hover:text-blue-600 inline-flex items-center gap-1 text-xs px-2"
              >
                <span>📋</span>
                <span className="hidden sm:inline">複製</span>
              </button>
            )}
            <button onClick={onDelete} title="刪除專案" className="p-1.5 hover:bg-rose-50 rounded text-slate-400 hover:text-rose-600">
              <Trash2 className="w-4 h-4" />
            </button>
            <button onClick={onClose} className="p-1.5 hover:bg-slate-100 rounded">
              <X className="w-5 h-5 text-slate-500" />
            </button>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-5 space-y-5">
          <section>
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-x-4 gap-y-3">
              <InfoField label="供應商" value={project.supplier} onSave={(v) => onUpdateField('supplier', v)} />
              <InfoField label="ID 設計" value={project.idDesigner} onSave={(v) => onUpdateField('idDesigner', v)} />
              <InfoField label="3D 設計" value={project.threeDDesigner} onSave={(v) => onUpdateField('threeDDesigner', v)} />
              <InfoField
                label="類別"
                value={project.category || deriveCategoryFromCode(project.code)}
                placeholder={deriveCategoryFromCode(project.code) ? '依料號自動帶入' : ''}
                onSave={(v) => onUpdateField('category', v)}
              />
              <InfoField label="開案日" value={project.openDate} type="date" onSave={(v) => onUpdateField('openDate', v)} />
            </div>
          </section>

          <EmailSubjectSection
            project={project}
            onChange={(v) => onUpdateField('emailSubjects', v)}
          />

          <section>
            <div className="flex items-center justify-between mb-2">
              <h3 className="text-xs font-medium text-slate-700 uppercase tracking-wide">標籤</h3>
            </div>
            <div className="flex flex-wrap gap-1.5 items-center">
              {(project.tags || []).map(t => (
                <span key={t} className="inline-flex items-center gap-1 text-xs px-2 py-1 rounded bg-violet-50 text-violet-700 border border-violet-200">
                  {t}
                  <button onClick={() => handleRemoveTag(t)} className="hover:text-violet-900">
                    <X className="w-3 h-3" />
                  </button>
                </span>
              ))}
              <div className="inline-flex items-center gap-1">
                <input
                  type="text"
                  value={newTag}
                  onChange={(e) => setNewTag(e.target.value)}
                  onKeyDown={(e) => { if (e.key === 'Enter') handleAddTag(); }}
                  placeholder="+ 新增標籤"
                  list="all-tags"
                  className="text-xs px-2 py-1 border border-slate-200 rounded w-28 focus:outline-none focus:border-slate-400"
                />
                <datalist id="all-tags">
                  {allTags.map(t => <option key={t} value={t} />)}
                </datalist>
                {newTag && (
                  <button onClick={handleAddTag} className="text-xs text-blue-600 hover:underline">加入</button>
                )}
              </div>
            </div>
          </section>

          <ProductImagesSection
            images={project.productImages || []}
            onChange={(imgs) => onUpdateField('productImages', imgs)}
          />

          <PhaseTimeline
            project={project}
            onOverride={(phase) => onUpdateField('phaseOverride', phase)}
          />


          <section id="pd-progress">
            <div className="flex items-center justify-between mb-2">
              <h3 className="text-xs font-medium text-slate-700 uppercase tracking-wide">進度紀錄</h3>
              <div className="flex items-center gap-1.5">
                <button
                  onClick={() => setShowEmailImport(true)}
                  title="從 Outlook 郵件自動帶入進度"
                  className="flex items-center gap-1 text-xs text-slate-500 hover:text-blue-700 hover:bg-blue-50 px-2 py-1 rounded"
                >
                  <span>📧</span>從郵件帶入
                </button>
                <button
                  onClick={() => setShowAddUpdate(true)}
                  className="flex items-center gap-1 text-xs text-blue-600 hover:text-blue-800 font-medium"
                >
                  <Plus className="w-3 h-3" />
                  新增更新
                </button>
              </div>
            </div>

            {showAddUpdate && (
              <>
                {followUpInitial && (
                  <p className="text-[11px] text-emerald-700 font-medium mb-1.5 px-1">✓ 記錄這次跟追結果，並可設定下次跟追日期</p>
                )}
                <UpdateForm
                  initial={followUpInitial || undefined}
                  onCancel={() => { setShowAddUpdate(false); setFollowUpInitial(null); }}
                  onSave={(u) => {
                    onAddUpdate(u);
                    // 如果是從跟追觸發的，同時標記舊的已跟追
                    if (followUpInitial?._triggerUpdate) {
                      const trigger = followUpInitial._triggerUpdate;
                      const updates = project.updates || [];
                      const idx = updates.findIndex(x => x.date === trigger.date && x.text === trigger.text);
                      if (idx >= 0) {
                        const newUpdates = [...updates];
                        newUpdates[idx] = { ...newUpdates[idx], followedUp: true };
                        onUpdateField('updates', newUpdates);
                      }
                    }
                    setShowAddUpdate(false);
                    setFollowUpInitial(null);
                  }}
                  currentUser={currentUser}
                />
              </>
            )}

            {showEmailImport && (
              <EmailImportModal
                project={project}
                onImport={(u) => { onAddUpdate(u); }}
                onClose={() => setShowEmailImport(false)}
              />
            )}

            {updates.length === 0 && !showAddUpdate ? (
              <p className="text-sm text-slate-400 py-4 text-center bg-slate-50 rounded-lg">尚無更新紀錄</p>
            ) : (
              <div className="relative pl-6">
                {/* 時間軸垂直線 */}
                <div className="absolute left-[7px] top-3 bottom-3 w-px"
                  style={{ background: 'linear-gradient(to bottom, #93c5fd, #e2e8f0 40%, #f1f5f9)' }} />
                <div className="space-y-2.5">
                {latest && (
                  <div className="relative">
                    <span className="absolute w-[9px] h-[9px] rounded-full bg-blue-500"
                      style={{ left: '-21px', top: '16px', boxShadow: '0 0 0 3px rgba(191, 219, 254, 0.8), 0 0 10px rgba(59, 130, 246, 0.4)' }} />
                    <UpdateCard
                    update={latest}
                    isLatest
                    isEditing={editingUpdateIdx === 0}
                    onStartEdit={() => setEditingUpdateIdx(0)}
                    onCancelEdit={() => setEditingUpdateIdx(null)}
                    onSave={(u) => { onEditUpdate(0, u); setEditingUpdateIdx(null); }}
                    onDelete={() => onDeleteUpdate(0)}
                    onMarkFollowedUp={isViewer ? null : handleMarkFollowedUp}
                    onAddUpdate={isViewer ? null : onAddUpdate}
                    onSetFollowUpDate={isViewer ? null : handleSetFollowUpDate}
                    currentUser={currentUser}
                    />
                  </div>
                )}

                {history.length > 0 && (
                  <button
                    onClick={() => setShowHistory(!showHistory)}
                    className="w-full flex items-center gap-1.5 text-xs text-slate-500 hover:text-slate-700 px-2 py-1"
                  >
                    {showHistory ? <ChevronDown className="w-3.5 h-3.5" /> : <ChevronRight className="w-3.5 h-3.5" />}
                    歷史紀錄 ({history.length})
                  </button>
                )}

                {showHistory && history.map((u, i) => (
                  <div key={i} className="relative">
                    <span className="absolute w-[7px] h-[7px] rounded-full bg-slate-300"
                      style={{ left: '-20px', top: '17px', boxShadow: '0 0 0 2px rgba(241, 245, 249, 1)' }} />
                    <UpdateCard
                    update={u}
                    isLatest={false}
                    isEditing={editingUpdateIdx === i + 1}
                    onStartEdit={() => setEditingUpdateIdx(i + 1)}
                    onCancelEdit={() => setEditingUpdateIdx(null)}
                    onSave={(updated) => { onEditUpdate(i + 1, updated); setEditingUpdateIdx(null); }}
                    onDelete={() => onDeleteUpdate(i + 1)}
                    onMarkFollowedUp={isViewer ? null : handleMarkFollowedUp}
                    onAddUpdate={isViewer ? null : onAddUpdate}
                    onSetFollowUpDate={isViewer ? null : handleSetFollowUpDate}
                    currentUser={currentUser}
                    />
                  </div>
                ))}
                </div>
              </div>
            )}
          </section>
          <div id="pd-design"><DesignSection
            designs={project.designs || { ID: [], '3D': [], BOM: [] }}
            onChange={(d) => onUpdateField('designs', d)}
          /></div>

          <div id="pd-dfm"><DFMSection
            hasDFM={project.hasDFM || false}
            dfmNotes={project.dfmNotes || ''}
            dfmAttachments={project.dfmAttachments || []}
            onToggle={(v) => onUpdateField('hasDFM', v)}
            onNotesChange={(v) => onUpdateField('dfmNotes', v)}
            onAttachmentsChange={(v) => onUpdateField('dfmAttachments', v)}
          /></div>

          <div id="pd-samples"><RelatedSamplesSection
            project={project}
            samples={samples}
            withdrawals={withdrawals}
            customerLists={customerLists}
            readOnly={isViewer}
          /></div>

          <div id="pd-proto"><PrototypeSection
            orders={project.prototypeOrders || []}
            onChange={(o) => onUpdateField('prototypeOrders', o)}
            defaultSupplier={project.supplier}
            readOnly={isViewer}
            designs={project.designs}
          /></div>

          <div id="pd-mould"><MouldSection
            orders={project.mouldOrders || []}
            onChange={(o) => onUpdateField('mouldOrders', o)}
            defaultSupplier={project.supplier}
            readOnly={isViewer}
          /></div>

          <div id="pd-trial"><TrialSection
            trialRuns={project.trialRuns || []}
            trialNotes={project.trialNotes || ''}
            onChangeRuns={(r) => onUpdateField('trialRuns', r)}
            onChangeNotes={(v) => onUpdateField('trialNotes', v)}
          /></div>

          <div id="pd-code"><MaterialCodeSection
            status={project.materialCodeStatus || '未申請'}
            materialCode={project.materialCodeNumber || ''}
            rfpAttachments={project.rfpAttachments || []}
            onChange={(v) => onUpdateField('materialCodeStatus', v)}
            onCodeChange={(v) => onUpdateField('materialCodeNumber', v)}
            onRfpChange={(v) => onUpdateField('rfpAttachments', v)}
            readOnly={isViewer}
            onGenerateRFP={() => setShowRFP(true)}
            hasDraft={!!project.rfpDraft}
          /></div>

          {/* 開發費用摘要 */}
          <div id="pd-cost"><DevCostSection
            project={project}
            isViewer={isViewer}
            onUpdateField={onUpdateField}
            samples={samples}
          /></div>

          <section>
            <h3 className="text-xs font-medium text-slate-700 uppercase tracking-wide mb-2">備註 / 特色</h3>
            {editingField === 'notes' ? (
              <div>
                <textarea
                  value={tempValue}
                  onChange={(e) => setTempValue(e.target.value)}
                  rows={3}
                  autoFocus
                  className="w-full px-3 py-2 text-sm border border-slate-300 rounded-lg focus:outline-none focus:border-slate-400 resize-none"
                />
                <div className="flex gap-2 mt-2">
                  <button onClick={saveField} className="text-xs px-3 py-1 bg-slate-900 text-white rounded">儲存</button>
                  <button onClick={() => setEditingField(null)} className="text-xs px-3 py-1 hover:bg-slate-100 rounded">取消</button>
                </div>
              </div>
            ) : (
              <div
                onClick={() => startEditField('notes', project.notes)}
                className="text-sm text-slate-700 leading-relaxed cursor-text hover:bg-slate-50 px-3 py-2 -mx-3 rounded-lg whitespace-pre-wrap min-h-[2.5rem]"
              >
                {project.notes || <span className="text-slate-400">點擊新增備註...</span>}
              </div>
            )}
          </section>
        </div>
      </div>

      {showWizard && (
        <ProductCodeWizard
          existingCodes={existingCodes}
          categoryCodes={categoryCodes}
          featureCodes={featureCodes}
          onApply={(code) => {
            onUpdateField('code', code);
            closeWizard();
          }}
          onClose={closeWizard}
        />
      )}

      {showRFP && (
        <RFPModal
          project={project}
          currentUser={currentUser}
          onClose={() => setShowRFP(false)}
          onSaveDraft={(draft) => onUpdateField('rfpDraft', draft)}
        />
      )}

      {/* 跟追完成對話框 */}
      {showFollowUpPrompt && followUpInitial && (
        <FollowUpDialog
          currentUser={currentUser}
          onComplete={({ text, nextFollowUpDate }) => {
            const trigger = followUpInitial._triggerUpdate;
            const todayStr = new Date().toISOString().split('T')[0];
            // 先把觸發的舊進度標記已跟追
            if (trigger) {
              const allUpdates = project.updates || [];
              const idx = allUpdates.findIndex(x => x.date === trigger.date && x.text === trigger.text);
              if (idx >= 0) {
                const newUpdates = [...allUpdates];
                newUpdates[idx] = { ...newUpdates[idx], followedUp: true };
                onUpdateField('updates', newUpdates);
              }
            }
            // 有進度：新增一筆
            if (text.trim()) {
              onAddUpdate({
                date: todayStr,
                text: text.trim(),
                author: currentUser?.name || '',
                followUpDate: nextFollowUpDate || null,
                followedUp: false,
              });
            } else if (nextFollowUpDate) {
              // 沒進度但設了下次日期：新增記錄保留軌跡
              onAddUpdate({
                date: todayStr,
                text: `（無新進度，已排定下次跟追：${nextFollowUpDate}）`,
                author: currentUser?.name || '',
                followUpDate: nextFollowUpDate,
                followedUp: false,
              });
            }
            setFollowUpInitial(null);
            setShowFollowUpPrompt(false);
          }}
          onCancel={() => {
            setFollowUpInitial(null);
            setShowFollowUpPrompt(false);
          }}
        />
      )}
    </div>
  );
}

