// 上傳檔案到 Firebase Storage
// 下載檔案並保留原始檔名
// - 小檔案（fileSize < 5MB）：fetch→Blob 方式，可保留檔名
// - 大檔案或未知大小：window.open 讓瀏覽器直接處理，速度快
// - onStatusChange(msg)：更新按鈕狀態文字，傳 null 代表完成
async function downloadFile(url, filename, fileSize = 0, onStatusChange) {
  const LARGE_FILE_THRESHOLD = 5 * 1024 * 1024; // 5MB
  const isLargeFile = fileSize > LARGE_FILE_THRESHOLD;

  if (isLargeFile || !url.includes('firebasestorage')) {
    // 大檔案或非 Storage 連結 → 直接開新頁讓瀏覽器處理
    window.open(url, '_blank');
    return;
  }

  // 小檔案 → fetch+Blob 保留檔名
  if (onStatusChange) onStatusChange('下載中...');
  try {
    const res = await fetch(url, { mode: 'cors' });
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    const blob = await res.blob();
    const blobUrl = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = blobUrl;
    link.download = filename || '下載檔案';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    setTimeout(() => URL.revokeObjectURL(blobUrl), 1000);
  } catch (e) {
    console.error('下載失敗：', filename, e);
    window.open(url, '_blank');
  } finally {
    if (onStatusChange) onStatusChange(null);
  }
}

// 圖片壓縮：長邊最大 1600px，JPEG quality 0.82
async function compressImageFile(file) {
  if (!file.type.startsWith('image/') || file.type === 'image/gif') return file;
  return new Promise((resolve) => {
    const img = new Image();
    const url = URL.createObjectURL(file);
    img.onload = () => {
      const MAX = 1600;
      let { width, height } = img;
      if (width <= MAX && height <= MAX && file.size < 500 * 1024) {
        URL.revokeObjectURL(url);
        resolve(file); // 小圖不壓縮
        return;
      }
      if (width > height) {
        if (width > MAX) { height = Math.round(height * MAX / width); width = MAX; }
      } else {
        if (height > MAX) { width = Math.round(width * MAX / height); height = MAX; }
      }
      const canvas = document.createElement('canvas');
      canvas.width = width; canvas.height = height;
      canvas.getContext('2d').drawImage(img, 0, 0, width, height);
      URL.revokeObjectURL(url);
      canvas.toBlob((blob) => {
        const compressed = new File([blob], file.name.replace(/\.[^.]+$/, '.jpg'), { type: 'image/jpeg' });
        resolve(compressed);
      }, 'image/jpeg', 0.82);
    };
    img.onerror = () => { URL.revokeObjectURL(url); resolve(file); };
    img.src = url;
  });
}

async function uploadFileToStorage(file, onProgress) {
  const safeName = file.name.replace(/[^\w.-]/g, '_');
  const path = `${STORAGE_FOLDER}/${Date.now()}_${Math.random().toString(36).slice(2, 8)}_${safeName}`;
  const fileRef = storageRef(storage, path);
  const uploadTask = uploadBytesResumable(fileRef, file);
  return new Promise((resolve, reject) => {
    uploadTask.on('state_changed',
      (snap) => {
        if (onProgress) onProgress((snap.bytesTransferred / snap.totalBytes) * 100);
      },
      reject,
      async () => {
        const url = await getDownloadURL(uploadTask.snapshot.ref);
        resolve({ url, path, name: file.name, size: file.size, type: file.type });
      }
    );
  });
}

async function deleteFileFromStorage(path) {
  if (!path) return;
  try {
    await deleteObject(storageRef(storage, path));
  } catch (e) {
    console.warn('刪除 Storage 檔案失敗:', e.message);
  }
}

function getFileIcon(name = '', type = '') {
  const ext = (name.split('.').pop() || '').toLowerCase();
  if (type.startsWith('image/') || ['png', 'jpg', 'jpeg', 'gif', 'webp', 'svg'].includes(ext)) return '🖼️';
  if (ext === 'pdf' || type === 'application/pdf') return '📕';
  if (['xlsx', 'xls', 'csv'].includes(ext)) return '📊';
  if (['doc', 'docx'].includes(ext)) return '📝';
  if (['stp', 'step', 'iges', 'igs', 'stl', 'obj'].includes(ext)) return '🧊';
  if (['ppt', 'pptx'].includes(ext)) return '📊';
  if (['zip', 'rar', '7z'].includes(ext)) return '🗜️';
  return '📄';
}

function isImageFile(name = '', type = '') {
  const ext = (name.split('.').pop() || '').toLowerCase();
  return type.startsWith('image/') || ['png', 'jpg', 'jpeg', 'gif', 'webp'].includes(ext);
}

function isPdfFile(name = '', type = '') {
  const ext = (name.split('.').pop() || '').toLowerCase();
  return type === 'application/pdf' || ext === 'pdf';
}

function formatFileSize(bytes) {
  if (!bytes) return '';
  if (bytes < 1024) return `${bytes} B`;
  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
  return `${(bytes / 1024 / 1024).toFixed(1)} MB`;
}

